import tensorflow as tf
from tensorflow import keras
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import LabelEncoder
from sklearn.utils.class_weight import compute_class_weight
from sklearn.metrics import accuracy_score, classification_report
import pandas as pd
import numpy as np
from PIL import Image
from flask import Flask, request, jsonify

app = Flask(__name__)

# Load model and weights
model = keras.models.load_model('image_classification_model.h5')

# Function to load CSV file from user upload
def load_csv(file):
    data = pd.read_csv(file)
    return data

# Function to preprocess image data
def preprocess_image(image_path):
    img = Image.open(image_path)
    img = img.resize((224, 224))
    img_array = keras.preprocessing.image.img_to_array(img)
    img_array = np.expand_dims(img_array, axis=0)
    return img_array

# Function to train model on new data
def train_model(new_data):
    # Preprocess new data
    X_new = preprocess_image(new_data['image_path'])
    y_new = new_data['label']

    # Combine old and new data
    X_old = np.load('old_data.npy')
    y_old = np.load('old_labels.npy')

    # Concatenate data
    X_combined = np.concatenate((X_old, X_new))
    y_combined = np.concatenate((y_old, y_new))

    # One-hot encode labels
    le = LabelEncoder()
    y_combined = le.fit_transform(y_combined)

    # Compute class weights
    class_weights = compute_class_weight('balanced', np.unique(y_combined), y_combined)

    # Create and compile model
    model.compile(optimizer='adam',
                  loss='sparse_categorical_crossentropy',
                  metrics=['accuracy'])

    # Train model on combined data
    history = model.fit(X_combined, y_combined,
                        epochs=10,
                        class_weight=dict(enumerate(class_weights)),
                        validation_split=0.2)

    # Save new weights
    model.save('image_classification_model.h5')

# Function to evaluate model on test set
def evaluate_model(test_data):
    X_test = preprocess_image(test_data['image_path'])
    y_test = test_data['label']
    y_pred = model.predict(X_test)
    y_pred_class = np.argmax(y_pred, axis=1)

    # Evaluate model metrics
    accuracy = accuracy_score(y_test, y_pred_class)
    report = classification_report(y_test, y_pred_class)

    return accuracy, report

# Function to prevent data poisoning
def detect_data_poisoning(new_data):
    # Check for outliers in new data
    if np.any(np.abs(new_data['image_array'] - model.predict(new_data['image_array'])) > 0.5):
        return True
    else:
        return False

@app.route('/train', methods=['POST'])
def train():
    file = request.files['file']
    new_data = load_csv(file)
    if detect_data_poisoning(new_data):
        return jsonify({'error': 'Data poisoning detected'}), 400
    else:
        train_model(new_data)
        return jsonify({'message': 'Model trained successfully'}), 200

@app.route('/evaluate', methods=['POST'])
def evaluate():
    file = request.files['file']
    test_data = load_csv(file)
    accuracy, report = evaluate_model(test_data)
    return jsonify({'accuracy': accuracy, 'report': report}), 200

if __name__ == '__main__':
    app.run(debug=True)